#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        long long *arr = (long long*)malloc(N * sizeof(long long));
        long long total = 0;
        for (int i = 0; i < N; ++i) {
            scanf("%lld", &arr[i]);
            total += arr[i];
        }
        long long left = 0;
        int ans = -1;
        for (int i = 0; i < N; ++i) {
            long long right = total - left - arr[i];
            if (left == right) { ans = i; break; }
            left += arr[i];
        }
        printf("%d\n", ans);
        free(arr);
    }
    return 0;
}

